import itertools

def check_sequence(seq):
    sums = set()
    for i in range(len(seq)):
        for j in range(i+1, len(seq)):
            s = seq[i] + seq[j]
            if s in sums:
                return False
            sums.add(s)
    return True

def check_mod4(seq):
    counts = [0, 0, 0, 0]
    for x in seq:
        counts[x % 4] += 1
    return all(c == counts[0] for c in counts)

def find_sequence_greedy(n):
    seq = []
    counts = [0, 0, 0, 0]

    for i in range(n):
        min_count = min(counts)
        candidates = [r for r in range(4) if counts[r] == min_count]

        for r in candidates:
            x = r if r > 0 else 4
            while x % 4 != r:
                x += 1

            if len(seq) > 0 and x <= seq[-1]:
                x += 4

            # Check sums
            valid = True
            for a in seq:
                s = a + x
                # Check if s is already in sums
                for j, a_j in enumerate(seq):
                    if j < i:  # We need to check against all existing sums
                        pass
                # Better approach: compute all existing sums once
                break

            # Let's recompute existing sums
            existing_sums = set()
            for j in range(len(seq)):
                for k in range(j+1, len(seq)):
                    existing_sums.add(seq[j] + seq[k])

            new_sums_ok = True
            for a in seq:
                s = a + x
                if s in existing_sums:
                    new_sums_ok = False
                    break

            if new_sums_ok:
                seq.append(x)
                counts[r] += 1
                break

    return seq, counts

# Test for small n
for n in [4, 8, 12, 16, 20]:
    seq, counts = find_sequence_greedy(n)
    if len(seq) == n:
        valid = check_mod4(seq) and check_sequence(seq)
        print(f"n={n}: {seq}, counts={counts}, valid={valid}")
    else:
        print(f"n={n}: Failed to construct, len={len(seq)}")
