def extend_sequence(base, target_n, max_val):
    n_base = len(base)
    needed = target_n - n_base

    counts = [0, 0, 0, 0]
    for x in base:
        counts[x % 4] += 1

    seq = list(base)
    new_counts = list(counts)
    target_count = target_n // 4

    for _ in range(needed):
        found = False
        for x in range(1, max_val):
            if x <= seq[-1]:
                continue

            r = x % 4
            if new_counts[r] < target_count:
                valid = True
                for a in seq:
                    s = a + x
                    for i in range(len(seq)):
                        for j in range(i+1, len(seq)):
                            if seq[i] + seq[j] == s:
                                valid = False
                                break
                        if not valid:
                            break
                    if not valid:
                        break

                if valid:
                    seq.append(x)
                    new_counts[r] += 1
                    found = True
                    break

        if not found:
            return None

    return seq

